"""ATR Breakout — ATR通道突破（短周期专用）"""
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class ATRBreakoutConfig:
    period: int = 7
    multiplier: float = 1.5


class ATRBreakout(Strategy):
    def __init__(self, exchange=None, config: Optional[ATRBreakoutConfig] = None):
        self.exchange = exchange
        self.config = config or ATRBreakoutConfig()

    @property
    def name(self) -> str:
        return "atr_breakout"

    def _atr(self, klines, period):
        trs = []
        for i in range(1, len(klines)):
            hl = klines[i]["high"] - klines[i]["low"]
            hc = abs(klines[i]["high"] - klines[i - 1]["close"])
            lc = abs(klines[i]["low"] - klines[i - 1]["close"])
            trs.append(max(hl, hc, lc))
        if len(trs) < period:
            return sum(trs) / len(trs) if trs else 0
        return sum(trs[-period:]) / period

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        p = self.config.period
        if not klines or len(klines) < p + 2:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        atr = self._atr(klines[:-1], p)
        prev_close = klines[-2]["close"]
        close = klines[-1]["close"]
        upper = prev_close + self.config.multiplier * atr
        lower = prev_close - self.config.multiplier * atr

        prev_atr = self._atr(klines[:-2], p)
        prev_prev_close = klines[-3]["close"]
        prev_upper = prev_prev_close + self.config.multiplier * prev_atr
        prev_lower = prev_prev_close - self.config.multiplier * prev_atr

        if close > upper and prev_close <= prev_upper:
            signal = Signal.BUY
        elif close < lower and prev_close >= prev_lower:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=0.7,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"atr": atr, "upper": upper, "lower": lower, "close": close})

